"""
mkt-original layer — Acts chapters 27–28
Output: data/commentary/mkt-original/acts.json
Run: python3 scripts/zc-original-acts-27-28.py

Key translation decisions for this range:
- elpis (27:20; 28:20): 'hope' — the Greek word covers both subjective feeling of confidence
  and objective expectation; 27:20 is the existential despair ('gave up all hope of being saved');
  28:20 is the theological 'hope of Israel' = the resurrection hope anchored in the promises to
  Abraham, fulfilled in Jesus (Acts 23:6; 24:15; 26:6-7)
- pneuma hagion (28:25): 'Holy Spirit' — pneuma (disp=3) + hagios (disp=2); the MKT capitalizes
  both; the attribution of Isa 6:9-10 to the 'Holy Spirit' identifies the Spirit as the author of
  OT prophecy; patēr (28:25) = 'your fathers' (the historical Israel to whom Isaiah spoke)
- nomos (28:23): 'Law of Moses' — the Torah as a body of covenant legislation; Paul 'explaining
  and testifying about the kingdom of God and trying to persuade them about Jesus from the Law of
  Moses and the Prophets' is the two-covenant-witnesses formula (Torah + Prophets)
- theos (27:23-25, 35; 28:6, 15, 23, 28, 31): 'God' throughout — the disp=2 reflects the generic
  Greek usage but in Acts the referent is always the God of Israel/Father; 28:6 where the Maltese
  think Paul is a 'god' is the only exception (lowercase in MKT; the same cheiropoiētoi contrast
  as 19:26)
- nekros (28:6): 'dead' (disp=2) — in 'they thought he would fall dead'; not 'dead person' in
  the technical resurrection sense but the ordinary sense of a corpse
- patēr (28:8): 'father' (disp=2) — 'the father of Publius'; the family-relation sense, not
  the theological 'Father'
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output (no duplicate or overwritten entries).
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ACTS_CH27_28 = {
"27": {
"1": "<p>'When it was decided that we would sail for Italy, Paul and some other prisoners were handed over to a centurion named Julius, who belonged to the Imperial Regiment' — the 'we' (hēmas — us) resumes the we-narrative that began at 16:10, dropped at 17:1, resumed at 20:5, and continues now through the Rome arrival. Luke's presence in the voyage is a firsthand claim for the narrative's accuracy. The 'Imperial Regiment' (Sebastēs speirēs — Augustan cohort) is an elite designation; Julius's rank and regiment explain the preferential treatment Paul receives (v.3). Acts 27 is the most detailed sea-voyage narrative in ancient literature, with precise nautical terminology throughout.</p>",
"2": "<p>'We boarded a ship from Adramyttium about to sail for ports along the coasts of the province of Asia, and we put out to sea. Aristarchus, a Macedonian from Thessalonica, was with us' — the Adramyttium ship (Adramyttēnō ploiō — a ship belonging to Adramyttium, a port on the Asia Minor coast) is a coastal vessel making local runs, not a direct Italy-bound ship; Julius must find a connecting vessel. Aristarchus (Acts 19:29; 20:4; Col 4:10; Phlm 24) is Paul's Thessalonian companion who was seized in the Ephesian riot — his presence on the prison ship suggests he traveled as Paul's 'slave' (a common legal fiction allowing companions to accompany prisoners).</p>",
"3": "<p>'The next day we landed at Sidon; and Julius, in kindness to Paul (philanthrōpōs — philanthropically/humanely), allowed him to go to his friends so they might provide for his needs' — philanthrōpōs (with human-kindness, humanely) is the word for the Roman humanitarian ideal: Julius treats Paul as a person of dignity rather than merely a prisoner. 'To his friends' (pros tous philous — to the friends/beloved) — the Sidon Christian community. The pattern of Paul's personal liberty within custody (receiving visitors, writing letters, preaching) continues throughout his imprisonment in Acts (23:16; 24:23; 27:3; 28:16, 30).</p>",
"4": "<p>'From there we put out to sea again and passed to the lee of Cyprus because the winds were against us' — the route from Sidon to Myra (v.5) requires sailing north of Cyprus to gain shelter from the prevailing NW Etesian winds. The nautical detail ('passed to the lee' — hypepleusamēn — sailed under the wind-shadow of Cyprus) is exactly the seamanship a knowledgeable observer would record. Luke's narrative is not a theological allegory but a maritime diary with theological significance — the voyage's dangers are real dangers that real seamanship addressed.</p>",
"5": "<p>'When we had sailed across the open sea off the coast of Cilicia and Pamphylia, we landed at Myra in Lycia' — the open-sea passage (pelagos — deep open sea, not coastal waters) off Cilicia and Pamphylia covers the southern Turkish coast, where the sea is exposed without shelter. Myra (modern Demre) in Lycia was a major port where Alexandrian grain ships stopped on their way to Italy — the centurion's transfer to an Alexandrian ship (v.6) is not coincidental but reflects the standard route of the Alexandrian grain fleet.</p>",
"6": "<p>'There the centurion found an Alexandrian ship sailing for Italy and put us on board' — the Alexandrian grain fleet was the lifeline of Rome: Egypt supplied a large portion of Rome's grain, and the great cargo ships (navis oneraria — merchant/cargo ships) that carried it were among the largest vessels of antiquity. Being placed on such a vessel (276 people in v.37 is consistent with large grain-ship capacity) means traveling on a ship whose commercial importance gave it relative priority in Mediterranean transit. The centurion's authority allows him to commandeer passage on the grain ship.</p>",
"7": "<p>'We made slow headway for many days and had difficulty arriving off Cnidus. When the wind did not allow us to hold our course, we sailed to the lee of Crete, opposite Salmone' — the slow progress (bradyploeountes — slow-sailing, a rare compound) and difficulty (molis — with difficulty, barely) reflects the NW headwinds that Alexandrian ships routinely struggled against in the late summer. Cnidus is at the SW tip of Asia Minor; from there the ship should have turned north into the Aegean but the winds forced it south under Crete. Salmone is Crete's NE cape.</p>",
"8": "<p>'We moved along the coast with difficulty and came to a place called Fair Havens, near the town of Lasea' — Fair Havens (Kaloi Limenes — Beautiful Harbors) is a real anchorage on Crete's south coast, still known by this name. The detailed place-names (Lasea, Fair Havens, later Phoenix — v.12) demonstrate that Luke is not composing a generic sea-voyage but recording a specific itinerary that can be followed on a map. The mention of Lasea as a nearby town anchors the account geographically.</p>",
"9": "<p>'Much time had been lost, and sailing had already become dangerous because by now it was after the Day of Atonement (tēn nēsteian — the Fast). So Paul warned them' — the Fast (hē nēsteia — the fasting; Yom Kippur) falls in early October. Ancient navigation treatises identified the period from mid-September to early November as progressively dangerous and after mid-November as closed. The Jewish liturgical calendar thus provides the chronological marker for the dangerous season: the Day of Atonement has passed, and the Mediterranean is turning hostile. Paul's knowledge of navigation seasons adds another dimension to his authority in the crisis ahead.</p>",
"10": "<p>'Men, I can see that our voyage is going to be disastrous and bring great loss to ship and cargo, and to our own lives also' — Paul's prophetic warning (theōrō hoti — I perceive/see that) uses the vision-verb but functions here as practical discernment based on experience and divine awareness rather than a formal vision. The warning is not yet based on divine revelation (that comes in v.23-24) but on practical assessment of conditions. Paul the experienced traveler (2 Cor 11:25 — three times shipwrecked) has navigational wisdom alongside prophetic authority.</p>",
"11": "<p>'But the centurion, instead of listening to what Paul said, followed the advice of the pilot and of the owner of the ship' — the centurion's preference for professional navigators over the prisoner's counsel is entirely natural and legally appropriate. The nautical experts outrank Paul in maritime matters. Luke records the decision without editorializing; the narrative's subsequent development (the storm, Paul's angel-vision, his renewed authority) is the commentary on who should have been heeded.</p>",
"12": "<p>'Since the harbour was unsuitable to winter in, the majority decided that we should sail on, hoping to reach Phoenix and winter there' — Phoenix (Phoinika — modern Loutra) was a harbor on the SW coast of Crete that faced SW and NW — offering protection from the dangerous winter storms from NE. The decision is a calculated risk: leave the inadequate anchorage at Fair Havens for the better harbor 50 miles west. 'The majority' (hoi pleiones — the greater number) — a formal decision by vote of the significant parties: pilot, owner, centurion, and perhaps others.</p>",
"13": "<p>'When a gentle south wind began to blow, they saw their opportunity; so they weighed anchor and sailed along the shore of Crete' — the southerly (notos — south wind) gave the ship a favorable push westward along Crete's south coast. 'Thinking that they had obtained what they desired' (doxantes tēs protheseōs kekratēkenai — thinking they had mastered their purpose) — the sailors' confidence that conditions have aligned with their plans is immediately refuted. The southerly is a brief window before the violent NE wind that will follow; favorable conditions are not divine approval.</p>",
"14": "<p>'Before very long, a wind of hurricane force, called the Northeaster (Eurakylōn), swept down from the island' — the Eurakylōn (a compound of the Greek euros + Latin aquilo = east wind + north wind) is the Levantine name for the violent NE gale that blows off the Cretan mountains in winter. Luke's use of the sailors' technical name for the wind is a mark of authenticity: he records the mariners' vocabulary, not a generalized 'storm.' The wind's origin 'from the island' (kat' autēs — down from it, i.e., from Crete's mountains) explains its katabatic (descending) force.</p>",
"15": "<p>'The ship was caught by the storm and could not head into the wind; so we gave way to it and were driven along' — the nautical phrase 'could not head into the wind' (mē dynamenēs antophthalmein tō anemō — not able to look the wind in the face) is the seamanship term for a ship unable to beat upwind. 'We gave way' (epidontes — handing over, yielding) — the crew abandoned the attempt to maintain course and let the wind drive them. The ship is now entirely at the storm's mercy; human navigation has yielded to the elements.</p>",
"16": "<p>'As we passed to the lee of a small island called Cauda, we were hardly able to make the lifeboat secure' — Cauda (modern Gavdos, the southernmost Greek island, 23 miles SW of Crete) provided brief shelter for emergency repairs. 'Hardly able' (molis — with difficulty, barely) appears twice in the chapter (v.7, 16) emphasizing the sustained difficulty. The skaphē (lifeboat) was normally towed behind the ship; in heavy seas it would waterlog and sink, so bringing it aboard was urgent but extremely difficult work.</p>",
"17": "<p>'So the men hoisted it aboard. Then they passed ropes under the ship itself to hold it together. Fearing that they would run aground on the sandbars of Syrtis, they lowered the sea anchor and let the ship be driven along' — 'passed ropes under the ship' (hypozōnnyntes to ploion — undergirding the ship) is frapping: passing cables around the ship's hull to prevent the planks from working apart in heavy seas. The Syrtis (Syrtin — the Syrtis Major, shallow sandbar-filled waters off Libya's coast) was one of the ancient world's most feared navigational hazards. Lowering the sea anchor (skeuos — the gear, here likely a drag-anchor or bare spar) slowed the ship's drift.</p>",
"18": "<p>'We took such a violent battering from the storm that the next day they began to throw the cargo overboard' — ekbolēn epoiounto (they were making a throwing-out) — the jettisoning of cargo (ekbolē = throwing-out, a nautical technical term) is the standard emergency measure in Mediterranean storms. Losing the cargo was financial catastrophe for the ship's owner; it was the only way to lighten the ship and keep it afloat. The sequence of emergency measures — frapping (v.17), jettisoning cargo (v.18), jettisoning the ship's tackle (v.19) — shows the crew executing a rational response to a worsening situation.</p>",
"19": "<p>'On the third day, they threw the ship's tackle overboard with their own hands' — 'the ship's tackle' (skeuēn tou ploiou — the equipment of the ship) includes the spare yards, sails, ropes, and heavy equipment. 'With their own hands' (autokheiroi — with their own hands, personally) emphasizes that by the third day even the hands-off passengers (like Luke) were throwing equipment overboard. The desperation has passed beyond crew work to involve everyone aboard.</p>",
"20": "<p>'When neither sun nor stars appeared for many days and the storm continued raging, we finally gave up all hope (elpis — hope; disp=2) of being saved' — elpis (hope/confident expectation; disp=2) is here the existential confidence of survival: the crew has lost the practical confidence that anyone will survive. In ancient navigation, the sun by day and stars by night provided the only positional reference; multiple days of overcast deprived the crew of any knowledge of where they were or where they were heading. Paul's subsequent intervention will restore — through divine assurance rather than navigation — the hope the storm took away.</p>",
"21": "<p>'After the men had gone a long time without food, Paul stood up before them and said: Men, you should have taken my advice not to sail from Crete; then you would have spared yourselves this damage and loss' — the men's fasting (asitias — foodlessness, abstaining from food) is partly imposed by the conditions (preparing food in a storm-tossed ship is nearly impossible) and partly voluntary (seasickness, despair). Paul's retrospective ('you should have listened to me') is not triumphalism but the establishment of his prophetic credibility: the one whose first warning proved correct is about to deliver a second word that must be heeded.</p>",
"22": "<p>'But now I urge you to keep up your courage, because not one of you will be lost; only the ship will be destroyed' — the paradox of Paul's second prophecy: physical destruction (the ship) paired with total salvation (not one person will be lost). This distinction between property-loss and life-preservation is the specific content of the divine promise Paul is about to report. The command 'keep up your courage' (euthumeite — be of good cheer, take heart) is the word the Lord used to Paul in the Jerusalem temple vision (23:11 — 'take courage').</p>",
"23": "<p>'Last night an angel of the God to whom I belong and whom I serve (paristēmi — who I stand beside/serve) stood beside me' — the angel's appearance in the night parallels Cornelius's angel (10:3-7) and the Lord's appearance to Paul at Corinth (18:9) and Jerusalem (23:11). 'The God to whom I belong' (theō hou eimi — the God whose I am) — the possessive 'whose I am' is the covenant-belonging formula: Paul identifies himself as God's property, not merely God's servant. 'Whom I serve' (latreuō — whose cult/worship I perform) — the priestly-service term for devoted worship.</p>",
"24": "<p>'And said: Do not be afraid, Paul. You must stand trial before Caesar (dei se Kaisari parastēnai — it is necessary for you to stand before Caesar); and God has graciously given you the lives of all who sail with you' — dei (it is necessary) — the divine necessity-formula used throughout Luke-Acts for the events that must occur to fulfill God's redemptive plan (Luke 2:49; 4:43; 9:22; 24:7; Acts 9:16; 14:22; 19:21; 27:24). Paul must reach Rome because God has determined it; the storm cannot defeat what divine necessity requires. 'Graciously given' (kechāristai — has gifted as a charis-gift, perfect tense = completed and permanent) — 276 lives are Paul's gift from God to distribute; his presence on the ship is a saving mercy for everyone aboard.</p>",
"25": "<p>'So keep up your courage, men, for I have faith in God (pisteuō tō theō — I believe God; disp=2 for theos) that it will happen just as he told me' — 'I believe God' — not 'I believe in God' (pisteuō eis theon = faith directed toward God as object) but pisteuō tō theō (dative = I trust God's word, I credit his promise). The MKT 'I have faith in God' renders the dative correctly; Paul's confidence is trust in the specific divine word just received, not generalized piety. 'Just as he told me' — the precision of the divine word (ship destroyed, all lives saved) is what Paul trusts; he does not trust a general providence but a specific promise.</p>",
"26": "<p>'Nevertheless, we must run aground on some island' — the 'nevertheless' (eis nēson dé tina dei hēmas ekpesein — but it is necessary for us to fall on some island) completes the divine word: the ship will be lost but not the people, and the mechanism will be a grounding on an island (fulfilled at v.41-44, Malta). The dei (necessity) again — even the shipwreck is a divinely ordained event within God's preservation of Paul and his companions. Luke records Paul's prophecy before the event so the reader can see the fulfillment; this is Luke's authentication technique throughout Acts.</p>",
"27": "<p>'On the fourteenth night we were still being driven across the Adriatic Sea, when about midnight the sailors sensed they were approaching land' — the 'Adriatic Sea' (kata meson tou Adriou — in the middle of the Adriatic) in ancient usage extended south to include the sea between Italy and Greece, the Ionian Sea, and the waters south of Crete — not merely the modern Adriatic between Italy and Yugoslavia. Fourteen nights of storm-driving at the typical drift-rate would bring the ship from Cauda (near Crete) to the vicinity of Malta — the geography is consistent. The sailors' sensory detection ('sensed') probably means they heard breakers in the darkness.</p>",
"28": "<p>'They took soundings and found that the water was twenty metres deep. A short time later they took soundings again and found it was fifteen metres deep' — the depth soundings (bolisantes — dropping the lead-line) are recorded with nautical precision: 'twenty fathoms' (orguias eikosi — twenty arm-spans, approximately 36 meters) then 'fifteen fathoms' (pente kai deka — fifteen arm-spans, approximately 27 meters). The shallowing water confirms they are approaching a shore. The 'short time later' (brachy diastēsantes — after a small interval/distance) and the rapid decrease in depth suggests a steeply shelving approach to Malta's coast.</p>",
"29": "<p>'Fearing that we would be dashed against the rocks, they dropped four anchors from the stern and prayed for daylight' — ancient ships could anchor from either end; stern-anchoring keeps the bow (and thus the steering oars) pointing toward shore, enabling a controlled beaching attempt at first light. 'Four anchors' distributed the holding force and reduced the risk of any single anchor failing. 'Prayed for daylight' (ēuchonto hēmeran genesthai — they were wishing/praying for day to come) — even the pagan sailors pray; Paul's God is not the only one addressed during the crisis, though he is the only one who answers.</p>",
"30": "<p>'In an attempt to escape from the ship, the sailors let the lifeboat down into the sea, pretending they were going to lower some anchors from the bow' — the sailors' plan to abandon ship is a reasonable survival strategy from their perspective: escape in the lifeboat before the ship breaks up. 'Pretending' (prophasis — pretext/false reason) they were laying bow anchors gave them cover for lowering the lifeboat. The sailors know the bow-anchor story is false; the soldiers and passengers may not have known the difference. Paul sees through the ruse (or receives divine insight) and intervenes.</p>",
"31": "<p>'Then Paul said to the centurion and the soldiers: Unless these men stay with the ship, you cannot be saved' — Paul's warning to Julius uses a conditional that is also a divine-word transmission: the angel promised 276 people would be saved, but that promise requires everyone to remain aboard. The sailors' professional competence is needed for the controlled beaching attempt at dawn; their desertion would doom the remaining passengers. The divine promise is not unconditional in execution: it requires the human cooperation it prescribes.</p>",
"32": "<p>'So the soldiers cut the ropes that held the lifeboat and let it drift away' — the soldiers' decisive action (apekopsan — they cut off, aorist = decisive, immediate action) eliminates the escape option for everyone, including themselves. The irrevocability of cutting the lifeboat loose commits all 276 people to the ship's fate — exactly what the divine word required. Julius's decision to trust Paul's word over the sailors' professional judgment is the centurion's act of faith: he has watched Paul's prophecy prove accurate for two weeks.</p>",
"33": "<p>'Just before dawn Paul urged them all to eat. For the last fourteen days, he said, you have been in constant suspense and have gone without food — you have not eaten anything' — 'constant suspense' (prosdokōntes — waiting/expecting anxiously, present participle = ongoing anxious watching) has kept the crew in hypervigilant watchfulness for fourteen days. 'Gone without food' (asitoi diateleite — you have continued foodless) — the asitia (foodlessness) of v.21 confirmed. Paul's initiative in calling the community to eat before the final beaching attempt is a pastoral act: he recognizes that frightened, exhausted, starved people cannot execute the physical demands of survival.</p>",
"34": "<p>'Now I urge you to take some food. You need it to survive. Not one of you will lose a single hair from his head (thriks apo tēs kephalēs oudenos apoleitai — not a hair from the head of anyone will be lost)' — the 'not a hair' formula is the OT idiom for absolute divine protection (1 Sam 14:45; 2 Sam 14:11; 1 Kgs 1:52; Luke 21:18). Paul's guarantee of physical preservation uses covenant-protection language: God's word of preservation is as certain as his word of judgment. The contrast: the ship will be destroyed (v.22) but not a hair on any person will be lost — two specific, contrasting divine guarantees.</p>",
"35": "<p>'After he said this, he took some bread and gave thanks to God (eucharistēsen tō theō — gave eucharist/thanks to God; disp=2 for theos) in front of them all. Then he broke it and began to eat' — the Eucharistic sequence (took bread, gave thanks, broke it, ate) is identical to the sequence of the Last Supper (Luke 22:19 — took, gave thanks, broke, gave) and the Emmaus meal (Luke 24:30 — took, blessed, broke, gave). Luke does not call this a communion meal — Paul is not offering the Lord's Supper to 276 people including pagan sailors and soldiers — but he narrates it with the full eucharistic gesture-sequence, allowing the reader to see that Paul's table-fellowship amid catastrophe bears the marks of the Lord's table.</p>",
"36": "<p>'They were all encouraged and ate some food themselves' — euthumoi genomoi (becoming cheerful/of good cheer) uses the same word as Paul's 'keep up your courage' (euthumeite) in v.22 and v.25. The food and Paul's assurance have done what fourteen days of storm could not: restored the crew's euthumia. The eating 'themselves' (kai autoi — even they) suggests that the pagan crew participated in the meal that Paul's prayer inaugurated — an unexpected table-fellowship across the gulf of religion, ethnicity, and social status.</p>",
"37": "<p>'Altogether there were 276 of us on board' — the number 276 (psychai diakosiai hebdomēkonta heks — 276 souls/lives) is a specific count that functions as a dramatic countdown to the promised preservation: 276 people will be saved, every single one. 'Souls' (psychai — souls, lives) is the OT idiom for persons (Gen 46:27 — 'seventy souls'). The number is also a check on the promise: if even one person fails to reach shore, the prophecy will have failed. Luke records the count precisely so the reader can verify that the divine word's 'not one will be lost' was exactly fulfilled.</p>",
"38": "<p>'When they had eaten as much as they wanted, they lightened the ship by throwing the grain into the sea' — the final jettisoning of the grain cargo (sitou ektyphloumenoi — throwing out the wheat/grain) is the last emergency measure: after eating to restore strength, the crew dumps everything heavy to maximize buoyancy for the beaching attempt. The grain was the ship's commercial cargo and the centurion's military supply; its loss is total economic ruin for the voyage but the only way to float the ship close enough to shore to swim.</p>",
"39": "<p>'When daylight came, they did not recognise the land, but they saw a bay with a sandy beach, where they decided to run the ship aground if they could' — the bay (kolpon — bay, bosom) with a sandy beach (aigialon — shoreline, beach) is the landing site. St Paul's Bay in Malta is consistently identified as the location; it has a sandy beach and the right depth profile for the sounding sequence of v.28. 'They decided to run the ship aground' (ebouleusanto exōsai to ploion eis ton aigialon — they resolved to drive/push the ship onto the beach) — a controlled beaching is the only remaining option.</p>",
"40": "<p>'Cutting loose the anchors, they left them in the sea and at the same time untied the ropes that held the rudders. Then they hoisted the foresail to the wind and made for the beach' — the sequence of actions is precise seamanship: (1) cut all four stern anchors free; (2) release the lashings that had secured the twin steering-oars during the storm (so they could be used to steer); (3) hoist the artemon (foresail — the small forward sail used for maneuvering, not driving) to give steerage-way. The detail is the description of someone who watched skilled sailors execute a practiced emergency procedure.</p>",
"41": "<p>'But the ship struck a sandbar and ran aground. The bow stuck fast and would not move, and the stern was broken to pieces by the pounding of the surf' — 'a place where two seas met' (topon dithalassonkataschon — a place of two seas) identifies a sandbar or reef where two currents converge, creating a shallowing ridge. The ship's bow drives onto the bar and lodges; the waves continue to strike the exposed stern, breaking it apart. The destruction is exactly as Paul prophesied (v.22 — 'only the ship will be destroyed'): the ship breaks up while all 276 people survive.</p>",
"42": "<p>'The soldiers planned to kill the prisoners to prevent any of them from swimming away and escaping' — Roman military law held a guard personally responsible for the escape of a prisoner; the soldiers' proposal to kill the prisoners rather than risk escape is legally rational. If the prisoners escape, the soldiers face execution in their place. The proposal is murderous but comprehensible within the Roman accountability structure — the same logic drove the Philippian jailer to draw his sword (16:27).</p>",
"43": "<p>'But the centurion wanted to spare Paul's life and kept them from carrying out their plan. He ordered those who could swim to jump overboard first and get to land' — Julius's protection of Paul (boulomenos diasōsai ton Paulon — desiring to save Paul thoroughly) is the centurion's decisive act of loyalty to the one whose prophecy has sustained 276 people for two weeks. The ordered evacuation — swimmers first — is military discipline applied to salvation: the strongest go first to provide help for the weaker on shore.</p>",
"44": "<p>'The rest were to get there on planks or on other pieces of the ship. In this way everyone reached land safely' — 'everyone' (panta — all, every person) is the fulfillment-word: the divine promise of v.22 ('not one of you will be lost') and v.34 ('not a hair of any of you will be lost') is fulfilled precisely. 276 people entered the water and 276 people reached land. The 'pieces of the ship' (apo tōn apo tou ploiou — from the things from the ship) are the broken planks of the stern (v.41) — the ship's destruction becomes the instrument of the passengers' salvation: the broken ship saves them.</p>"
},
"28": {
"1": "<p>'Once safely on shore, we found out that the island was called Malta' — diasōthentes (thoroughly saved/completely rescued — dia + sōzō, the salvation-verb) — the same verb root as Paul's promise 'you will be saved' (v.30, 31, 44). Luke's use of diasōzō at the moment of arrival on shore makes the landing a salvation-event: the promise of v.22-24 has been exactly fulfilled. Malta (Melitē — honey, from the Phoenician) was a Carthaginian and later Roman colony, strategically located in the central Mediterranean; its population was Punic-speaking, not Greek.</p>",
"2": "<p>'The islanders showed us unusual kindness (philanthropian — philanthropy/human-kindness). They built a fire and welcomed us all because it was raining and cold' — philanthropia (disp=0 but significant: the same root as Julius's philanthropōs in 27:3) is Luke's summary of Malta's reception: the pagan islanders demonstrate the human-kindness that the Roman centurion demonstrated — and that the Jerusalem mob failed to demonstrate. The fire (pyran — a bonfire), the welcome of 276 wet, cold, exhausted shipwreck survivors, is the practical form of the philanthropia. Luke repeatedly notes when pagan generosity exceeds religious community's self-protection.</p>",
"3": "<p>'Paul gathered a pile of brushwood and, as he put it on the fire, a viper, driven out by the heat, fastened itself on his hand' — Paul's participation in gathering firewood (phryganōn ti plēthos synstrephantos — gathering a multitude of sticks) is the apostolic pattern: he does not stand apart from manual labor (cf. 18:3; 20:34-35). The viper (echidna — a venomous snake) driven out by the fire's heat (apo tēs thermēs — from the heat) is a realistic detail; the creature was in the brushwood, seeking warmth, and biting defensively when disturbed. 'Fastened itself on his hand' (kathapsen tēs cheiros autou — seized/bit his hand) — the hold was enough to hang from his hand (v.4 — hanging from his hand).</p>",
"4": "<p>'When the islanders saw the snake hanging from his hand, they said to each other: This man must be a murderer; for though he escaped from the sea, Justice (Dikē) has not allowed him to live' — Dikē (Justice, Divine Justice) is the Greek goddess of retributive justice — the Maltese invoke her as the cosmic principle that punishes guilt even when human courts fail. The theological assumption is exact: the sea's survival proves innocence of sea-related sins; the snakebite suggests a guilt-beyond-survival. The Maltese reasoning is not ignorant superstition but follows a coherent Greek theological framework in which the gods close every escape route for the guilty.</p>",
"5": "<p>'But Paul shook the snake off into the fire and suffered no ill effects' — apotinaxas to thrion eis to pyr (shaking off the creature into the fire) — the casual, unhurried gesture ('shook off') rather than a panicked reaction suggests either divine calmness or divine protection; the narrative implies both. 'Suffered no ill effects' (ouden kakon epathen — he suffered nothing bad) — the Maltese expected swelling (prēsthai — to swell, v.6) and collapse. Neither came. The fulfillment of the snake-immunity promise (Luke 10:19 — 'I have given you authority to tread on serpents') enacted on Malta.</p>",
"6": "<p>'The people expected him to swell up or suddenly fall dead (nekron — dead; disp=2); but after waiting a long time and seeing nothing unusual happen to him, they changed their minds and said he was a god' — nekron (dead; disp=2) — the ordinary sense of a corpse, not the resurrection-technical sense. The Maltese theological inversion is complete: murderer → god; the same evidence (snake-bite + survival) that first confirmed his guilt now confirms his divinity. The crowd's oscillation mirrors the Lystra crowd's progression from 'the gods have come down to us' (14:11) to stoning (14:19) — pagan theological attribution is unstable. Luke records the divine-attribution without correcting it in this scene (contrast 14:14-15 where Paul and Barnabas refuse worship).</p>",
"7": "<p>'There was an estate nearby that belonged to Publius, the chief official (prōtō — first, leading official) of the island. He welcomed us to his home and showed us generous hospitality for three days' — 'Prōtos tēs nēsou' (the First of the island) is confirmed as an actual title by two Maltese inscriptions using exactly this Greek term. Luke's use of the official title is another authenticity marker: he records the correct administrative designation for Malta's Roman governor. Three days of generous hospitality (philophronōs — with lover-of-strangers kindness, philanthropy's sibling virtue) for 276 shipwreck survivors is a substantial logistical commitment.</p>",
"8": "<p>'His father (patēr — father; disp=2) was sick in bed, suffering from fever and dysentery. Paul went in to see him and, after prayer, placed his hands on him and healed him' — patēr (father; disp=2) in the domestic sense — Publius's biological father. The fever (pyretois — fevers, plural — indicating recurring or multiple fevers) combined with dysentery (dysenteria — bloody flux) is consistent with Malta Fever (brucellosis), endemic to Malta from unpasteurized goat's milk. 'After prayer' (proseuxamenos — having prayed) distinguishes Paul's healing from medical practice or magical technique: prayer acknowledges the divine source of the healing; 'placed his hands on him' is the physical channel; healing follows.</p>",
"9": "<p>'When this had happened, the rest of those on the island who had diseases came and were cured' — the healing of Publius's father becomes the occasion for a general healing mission: 'the rest of those who had diseases' (hoi loipoi hoi en tē nēsō echontes asthenias — the remaining ones on the island having illnesses) came to Paul. The pattern repeats: one high-status healing opens a community-wide healing mission (cf. Peter's mother-in-law healing → whole city gathers at sunset, Mark 1:32-34; Luke 4:40-41). Malta receives a ministry of healing that parallels the preaching-healing combination Paul conducted in cities throughout the journeys.</p>",
"10": "<p>'They honoured us in many ways; and when we were ready to sail, they furnished us with the supplies we needed' — 'honoured us in many ways' (pollais timais etīmēsan hēmas — they honoured us with many honours) — timē (honour, value) can refer to honorific recognition or to monetary compensation/payment; the latter is possible here (they paid them for the healing ministry). 'Furnished us with the supplies we needed' (tois pros tas chreias — the things toward the needs) — practical provisioning for the voyage continuation. The Malta interlude demonstrates the gospel's power to generate community (receiving, healing, mutual supply) even without a church established.</p>",
"11": "<p>'After three months we put out to sea in a ship that had wintered in the island — it was an Alexandrian ship with the figurehead of the twin gods Castor and Pollux' — the three months on Malta (October/November through January/February) is the closed-navigation period. The Alexandrian ship (another grain ship from the Egypt-Italy route, wintering at Malta) bears the figurehead Dioskouroi (Castor and Pollux — the twin sons of Zeus, patron deities of sailors, the constellation Gemini). The pagans on the ship travel under the protection of their sea-gods; Luke notes the figurehead without comment, letting the journey's safety under Paul's God speak for itself.</p>",
"12": "<p>'We put in at Syracuse and stayed there three days' — Syracuse (Syrakousas — the major Greek city on Sicily's SE coast) was the most important city in Sicily and a major port on the Italy-bound route. Three days there provided rest, provisioning, and perhaps contact with the local community. Luke's route-summary (Syracuse → Rhegium → Puteoli → Appian Way → Rome) is the standard Italy-arrival itinerary for Mediterranean ships and can be traced on a map with precision.</p>",
"13": "<p>'From there we set sail and arrived at Rhegium. The next day the south wind came up, and on the following day we reached Puteoli' — Rhegium (modern Reggio di Calabria) is at the toe of Italy, across the Strait of Messina from Sicily. The southerly (notos — south wind) that came up the next day at Rhegium enabled a fast run up Italy's west coast to Puteoli (modern Pozzuoli, near Naples), the main Italian port for Alexandrian grain ships. The two-day run from Rhegium to Puteoli is consistent with favorable southerly winds through the Strait of Messina.</p>",
"14": "<p>'There we found some brothers and sisters who invited us to spend a week with them. And so we came to Rome' — the Christians at Puteoli (not otherwise mentioned in the NT) represent the first Roman Christians Paul encounters: the gospel reached Italy before Paul did, through the network of travelers and traders. The seven-day stay (epimeinai par' autois hēmeras hepta — to remain with them seven days) required Julius's permission — he continues to treat Paul with the philanthropia established at Sidon. 'And so we came to Rome' — Luke's matter-of-fact announcement of the journey's end: Rome, the goal since 19:21.</p>",
"15": "<p>'The brothers and sisters there had heard that we were coming, and they travelled as far as the Forum of Appius and the Three Taverns to meet us. At the sight of these people Paul thanked God and was encouraged' — Roman Christians (not yet met by Paul) came 40+ miles (Forum of Appius on the Appian Way) and 30+ miles (Three Taverns, further toward Rome) to meet him. The coming-to-meet (eis apantēsin — for a meeting, for an encounter; this is the technical term for the formal civic reception of a dignitary — the parousia-reception formula) mirrors the language of 1 Thess 4:17 ('to meet the Lord in the air'). Paul's encouragers are the ones who came to escort him in to Rome. 'Thanked God and was encouraged' — the two responses to divine faithfulness: gratitude and renewed courage.</p>",
"16": "<p>'When we got to Rome, Paul was allowed to live by himself, with a soldier to guard him' — 'live by himself' (menein kath' heauton — to remain by himself, privately) — Paul is not imprisoned in the public jail but lives in his own rented accommodation (v.30 — en idiō misthōmati — in his own hired dwelling) under house arrest, with a single military guard. This custodia militaris (military custody) allowed him to receive visitors, write letters, and continue preaching — the form of imprisonment that produced Ephesians, Philippians, Colossians, and Philemon.</p>",
"17": "<p>'Three days later he called together the local Jewish leaders. When they had assembled, Paul said to them: My brothers, although I have done nothing against our people or against the customs of our ancestors, I was arrested in Jerusalem and handed over to the Romans' — Paul's immediate initiative toward the Roman Jewish community (synagogē archous — the synagogue leaders, the plural implies multiple Roman synagogues) follows his invariable pattern: to the Jew first. 'My brothers' (andres adelphoi — men, brothers) is Paul's standard synagogue address (13:15; 22:1; 23:1, 6; 28:17). His defense is pre-emptive: he establishes innocence (nothing against the people or the ancestral customs) before any accusation arrives.</p>",
"18": "<p>'They examined me and wanted to release me, because I was not guilty of any crime deserving death' — Paul's summary of the Roman judicial process (Felix, Festus, Agrippa — Acts 24-26) in one sentence: the consistent conclusion of three Roman officials was innocence (cf. 23:29 — Claudius Lysias; 25:25 — Festus; 26:31-32 — Agrippa). Luke has documented the legal innocence of Paul at length so that Paul's arrival at Rome as a prisoner cannot be misread as evidence of guilt; it is evidence of Jewish political pressure, not Roman legal condemnation.</p>",
"19": "<p>'When the Jews objected, I was compelled to make an appeal to Caesar. I certainly did not intend to bring any charge against my own nation' — Paul's appeal to Caesar (Acts 25:11) was defensive, not offensive: it was not to accuse the Jews before Caesar but to prevent the Jerusalem Sanhedrin from acquiring jurisdiction over his case. 'I certainly did not intend to bring any charge' (ōs tou ethnous mou echōn ti katēgorein — not as having anything to accuse my nation of) — the syntax of denial; Paul approaches Rome's Jews as a fellow Jew, not as an adversary.</p>",
"20": "<p>'For this reason I have asked to see you and talk with you. It is because of the hope of Israel (tēn elpida tou Israēl — the hope of Israel; disp=2 for elpis) that I am bound with this chain' — elpis tou Israēl (the hope of Israel) is the theological summary of Paul's entire mission: the hope = the resurrection (Acts 23:6; 24:15; 26:6-7), which is Israel's covenantal expectation. Paul's chain is not a Roman punishment for crime but a paradoxical badge of fidelity to Israel's own hope. The chain that binds him binds him to the promise that bound Abraham.</p>",
"21": "<p>'They replied: We have not received any letters from Judea concerning you, and none of our people who have come from there has reported or said anything bad about you' — the Roman Jewish community's ignorance of Paul is surprising given his prominence in Jerusalem's temple riots (21:27-36); either the Jerusalem leadership chose not to pursue the matter to Rome, or communications had not yet arrived. The Romans' openness (v.22 — 'we want to hear what your views are') gives Paul the opportunity he has had in every city: the receptive audience that precedes the decisive division.</p>",
"22": "<p>'But we want to hear what your views are, for we know that people everywhere are talking against this sect (haireseōs tautēs — this sect/choice/party)' — hairesis (sect, school of thought, disp=0 here but theologically significant) was the standard Greek term for a philosophical or religious movement defined by distinctive doctrines. The same word is used for the 'sect of the Nazarenes' (24:5) and Paul's own self-description of 'the Way which they call a sect' (24:14). The Roman Jews' description ('people everywhere are talking against this sect') confirms the movement's wide, if controversial, recognition.</p>",
"23": "<p>'They arranged to meet Paul on a certain day, and came in even larger numbers to the place where he was staying. He witnessed to them from morning till evening, explaining and testifying about the kingdom of God, and trying to persuade them about Jesus from the Law of Moses (nomou Mōyseōs — the Law of Moses; disp=3 for nomos) and the Prophets' — the 'morning till evening' exposition is the longest single preaching session recorded in Acts — Paul's full-day messianic demonstration from Torah and Prophets. The two-witness structure (Law of Moses + Prophets) is the standard prophetic-fulfillment argument (Luke 24:27, 44). The kingdom of God (v.23, 31) bookends the chapter: Acts begins with the disciples asking about the kingdom (1:3) and ends with Paul proclaiming it.</p>",
"24": "<p>'Some were convinced by what he said, but others would not believe' — the divided response (hoi men... hoi de — some... others) is the universal pattern of Paul's synagogue missions: Antioch (13:43-45), Iconium (14:1-2), Thessalonica (17:4-5), Berea (17:11-12), Corinth (18:4-8). The division is not accidental; it is the predicted consequence of the Isaiah word that Paul is about to quote. The division between believing Jews and unbelieving Jews does not end Jewish mission — it explains it theologically.</p>",
"25": "<p>'They disagreed among themselves and began to leave after Paul had made this final statement: The Holy Spirit (to pneuma to hagion — the Holy Spirit; disp=3 for pneuma, disp=2 for hagios) spoke the truth to your ancestors (dia Ēsaiou tou prophētou — through Isaiah the prophet) when he said' — Paul's attribution of Isaiah 6:9-10 to 'the Holy Spirit' makes the Spirit the author of OT prophecy: the prophetic word is simultaneously Isaiah's word and the Spirit's word. 'Your ancestors' (pateras hymōn — your fathers; disp=2 for patēr — the OT-covenant fathers to whom Isaiah originally spoke) — the quotation applies to both the original audience and their descendants who now stand before Paul.</p>",
"26": "<p>Already present.</p>",
"27": "<p>'For this people's heart has become calloused; they hardly hear with their ears, and they have closed their eyes. Otherwise they might see with their eyes, hear with their ears, understand with their hearts and turn, and I would heal them' — the Isaiah 6:9-10 citation (in its LXX form) is the most-quoted OT passage in the NT: Matthew (13:14-15), Mark (4:12), Luke (8:10), John (12:40), and now Acts 28:26-27 all apply it to Jewish unbelief. The LXX version emphasizes the people's own self-blinding ('they have closed their eyes' — ekammusan — aorist active, they closed) rather than the divine hardening of the Hebrew ('make their hearts fat'). The difference matters: the Greek version leaves more room for the culpability of the people who chose not to see.</p>",
"28": "<p>'Therefore I want you to know that God's salvation (to sōtērion tou theou — the salvation of God; disp=2 for theos) has been sent to the Gentiles, and they will listen!' — to sōtērion (the salvation, used as a noun) echoes the Nunc Dimittis (Luke 2:30 — 'for my eyes have seen your salvation') and Simeon's identification of Jesus as the sōtērion prepared before all peoples. Paul's final declaration to Rome's Jewish leaders repeats what has been said since Acts 13:46: the Gentile turn is a consequence of Jewish unbelief, not a replacement of Jewish priority. 'They will listen' (autoi kai akousontai — they indeed will hear/listen) — the Gentile receptivity that Isaiah's hardened-Israel passage implies by contrast.</p>",
"29": "<p>'After he said this, the Jews left, arguing vigorously among themselves' — verse 29 is omitted in most early MSS (it does not appear in p74, Aleph, A, B, E, or 33); it is present in later MSS and the Byzantine tradition. Many commentators consider it a scribal addition clarifying that the Jews departed. Whether original or not, its content is consistent with the narrative pattern: the divided-and-departing response (hoi men... hoi de — some... others, as in v.24) has occurred at every Paul-synagogue encounter; the argument among themselves is the community's internal division that the gospel always produces.</p>",
"30": "<p>'For two whole years Paul stayed there in his own rented house and welcomed all who came to see him' — the 'whole years' (holēn dietian — an entire two-year period) at Rome in custodia militaris produced the prison letters (Ephesians, Philippians, Colossians, Philemon) and the ongoing mission summarized in v.31. 'In his own rented house' (en idiō misthōmati — at his own expense) — Paul paid for his own lodging even under arrest; the manual labor and tent-making trade sustained him even in Rome. 'Welcomed all who came to see him' — the open-door policy of Paul's imprisonment: the chain does not imprison the gospel.</p>",
"31": "<p>'He proclaimed (kērassōn — heralding, preaching) the kingdom of God and taught about the Lord Jesus Christ — with all boldness (meta pasēs parrēsias — with all openness/freedom of speech) and without hindrance (akōlytōs — unhindered, prevented-by-no-one; the final word of the book)' — the book of Acts ends on akōlytōs — a single adverb meaning 'without hindrance, unimpeded.' The gospel has traveled from Jerusalem to Rome without final suppression; Paul preaches the kingdom and teaches the Lord Jesus with full parrēsia (bold free-speech) in the capital of the empire. The open ending — no mention of Paul's trial outcome, no resolution — is Luke's deliberate conclusion: the word of God is not bound (2 Tim 2:9); the story continues beyond any document's last page.</p>"
}
}

def main():
    existing = load_comm('mkt-original', 'acts')
    merge_comm(existing, ACTS_CH27_28)
    save_comm('mkt-original', 'acts', existing)
    ch27 = len(existing.get('27', {}))
    ch28 = len(existing.get('28', {}))
    print(f'Acts 27: {ch27}/44. Acts 28: {ch28}/31.')

if __name__ == '__main__':
    main()
